import React, { useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";
import "./verifyotp.css"; // Ensure you have the CSS file for styling

const VerifyOtpPage = () => {
  const [otp, setOtp] = useState("");
  const [otpError, setOtpError] = useState("");
  const [otpMessage, setOtpMessage] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);

  const navigate = useNavigate();

  const handleOtpSubmit = async (e) => {
    e.preventDefault();
    setOtpError("");
    setOtpMessage("");

    if (!otp.trim()) {
      setOtpError("OTP is required.");
      return;
    }

    if (!/^\d{6}$/.test(otp)) {
      setOtpError("Invalid OTP format. Must be 6 digits.");
      return;
    }

    try {
      setIsSubmitting(true);
      const response = await axios.post("http://localhost:5000/api/auth/verify-otp", { otp });

      if (response.data.success) {
        setOtpMessage("OTP Verified Successfully!");
        setTimeout(() => navigate("/reset-password"), 2000); // Redirect to reset password page
      } else {
        setOtpError(response.data.message);
      }
    } catch (err) {
      setOtpError("Error verifying OTP. Please try again.");
      console.error("OTP Verification Error:", err);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="verify-otp-container">
      <img src="/logo.png" alt="Logo" className="logo" />
      <div className="verify-otp-card">
        <h2>Verify OTP</h2>
        <p>Enter the 6-digit OTP sent to your email</p>
        <form onSubmit={handleOtpSubmit}>
          <div className="input-group">
            <span className="icon">🔒</span>
            <input
              type="text"
              placeholder="Enter OTP"
              value={otp}
              onChange={(e) => setOtp(e.target.value)}
              maxLength="6"
              required
              disabled={isSubmitting}
            />
          </div>
          <button type="submit" className="verify-otp-button" disabled={isSubmitting}>
            {isSubmitting ? "Verifying..." : "Verify OTP"}
          </button>
        </form>
        <div className="message-container">
          {otpMessage && <p className="success-message">{otpMessage}</p>}
          {otpError && <p className="error-message">{otpError}</p>}
        </div>
        <a href="/forgot-password" className="back-link">Resend OTP</a>
      </div>
    </div>
  );
};

export default VerifyOtpPage;
